/**
 * meme-directives-test.mjs
 *
 * Example deck generated by the /create-deck skill (pptxgenjs engine, default theme).
 * Source outline: examples/meme-directives-test/outline-with-directives.md
 *
 * This deck demonstrates LAYOUT: and IMAGE: directives in action — each slide uses
 * a different directive combination to show how the skill interprets them.
 *
 * Usage (run from the repo root):
 *   npm install -g pptxgenjs react react-dom react-dom-server react-icons sharp
 *   node examples/meme-directives-test/meme-directives-test.mjs
 *
 * Output: output/meme-directives-test.pptx
 *
 * Module format: ES Modules (import). Requires Node.js 14+.
 * Depends on lib/pptxgenjs-helpers.mjs and themes/default.yaml in the repo root.
 */

import { createRequire } from 'module';
const require = createRequire(import.meta.url);

import {
  createDeck, addTitleSlide, addBulletSlide, addProcessFlow,
  addTwoColumn, addCardGrid, addStatCallout, addCodeSlide,
  addIconRowsSlide, addSectionDivider, addClosingSlide,
  addFooter, renderIconSvg, iconToBase64, preRenderIcons,
  cardShadow, SW, SH,
} from '../../lib/pptxgenjs-helpers.mjs';

import { existsSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const OUTLINE_DIR = resolve(__dirname, '../outlines');

async function buildDeck() {
  const deck = createDeck('themes/default.yaml');
  const { pptx, theme, layout } = deck;
  const { M, CONTENT_W, CONTENT_Y, CONTENT_H } = layout;
  const C = theme.colors;
  let sn = 1;

  // Helper for image+bullets slides
  function addImageBulletsSlide(title, imagePath, bullets, slideNum) {
    const slide = pptx.addSlide();
    slide.background = { color: C.background };

    slide.addText(title, {
      x: M, y: 0.3, w: CONTENT_W, h: 0.7,
      fontSize: 28, fontFace: theme.fonts.heading,
      color: C.text_primary, bold: true,
    });

    const imgW = 5.5;
    const imgH = 4.0;
    const imgX = M;
    const imgY = CONTENT_Y + 0.1;

    if (existsSync(imagePath)) {
      // Image on the left
      slide.addImage({
        path: imagePath,
        x: imgX, y: imgY, w: imgW, h: imgH,
        sizing: { type: 'contain', w: imgW, h: imgH },
      });
    } else {
      // Placeholder rectangle
      slide.addShape(pptx.ShapeType.rect, {
        x: imgX, y: imgY, w: imgW, h: imgH,
        fill: { color: C.surface },
      });
      slide.addText(`[Image: ${imagePath}]`, {
        x: imgX, y: imgY, w: imgW, h: imgH,
        fontSize: 12, fontFace: theme.fonts.body,
        color: C.text_secondary, align: 'center', valign: 'middle',
      });
    }

    // Bullets on the right
    const bulletX = imgX + imgW + 0.4;
    const bulletW = CONTENT_W - imgW - 0.4;

    const textItems = bullets.map(b => ({
      text: b,
      options: {
        fontSize: 16, fontFace: theme.fonts.body,
        color: C.text_body, bullet: true,
        breakLine: true, paraSpaceAfter: 12,
      },
    }));

    slide.addText(textItems, {
      x: bulletX, y: imgY, w: bulletW, h: imgH,
      valign: 'top',
    });

    addFooter(slide, slideNum, theme);
    return slide;
  }

  // Helper for image-only slides (LAYOUT: diagram + IMAGE)
  function addImageSlide(title, imagePath, bullets, slideNum) {
    const slide = pptx.addSlide();
    slide.background = { color: C.background };

    slide.addText(title, {
      x: M, y: 0.3, w: CONTENT_W, h: 0.7,
      fontSize: 28, fontFace: theme.fonts.heading,
      color: C.text_primary, bold: true,
    });

    const imgW = 7.0;
    const imgH = 5.0;
    const imgX = (SW - imgW) / 2;
    const imgY = CONTENT_Y + 0.1;

    if (existsSync(imagePath)) {
      slide.addImage({
        path: imagePath,
        x: imgX, y: imgY, w: imgW, h: imgH,
        sizing: { type: 'contain', w: imgW, h: imgH },
      });
    } else {
      slide.addShape(pptx.ShapeType.rect, {
        x: imgX, y: imgY, w: imgW, h: imgH,
        fill: { color: C.surface },
      });
      slide.addText(`[Image: ${imagePath}]`, {
        x: imgX, y: imgY, w: imgW, h: imgH,
        fontSize: 14, fontFace: theme.fonts.body,
        color: C.text_secondary, align: 'center', valign: 'middle',
      });
    }

    // Add bullets as speaker notes
    if (bullets && bullets.length) {
      slide.addNotes(bullets.join('\n'));
    }

    addFooter(slide, slideNum, theme);
    return slide;
  }

  // ═══════════════════════════════════════════════════════════════
  // Slide 1 — Title: The Art of the Meme
  // ═══════════════════════════════════════════════════════════════
  addTitleSlide(deck, "The Art of the Meme",
    "A comprehensive guide to internet culture's finest moments", sn++);

  // ═══════════════════════════════════════════════════════════════
  // Slide 2 — This Is Fine (LAYOUT: diagram + IMAGE)
  // Full image with bullets as context
  // ═══════════════════════════════════════════════════════════════
  addImageBulletsSlide("This Is Fine",
    resolve(OUTLINE_DIR, 'memes/this-is-fine.jpg'),
    [
      "Dog sitting in a burning room, drinking coffee",
      "The universal symbol for every standup meeting ever",
      '"Everything is on track for the sprint deadline"',
      "First appeared in KC Green's Gunshow webcomic, 2013",
    ], sn++);

  // ═══════════════════════════════════════════════════════════════
  // Slide 3 — Two Types of Developers (LAYOUT: two_column)
  // ═══════════════════════════════════════════════════════════════
  addTwoColumn(deck, "Two Types of Developers",
    "Before Code Review", "After Code Review",
    [
      '"It works on my machine"',
      "Ship it, YOLO",
      "Comments? Documentation? Never heard of it",
      "400-line function? It's called efficiency",
    ],
    [
      "Added unit tests",
      "Refactored into small functions",
      "Documented the edge cases",
      "Wondering who wrote the original code (it was you)",
    ],
    sn++);

  // ═══════════════════════════════════════════════════════════════
  // Slide 4 — Stages of Debugging (LAYOUT: numbered, 6 steps)
  // ═══════════════════════════════════════════════════════════════
  addProcessFlow(deck, "Stages of Debugging", [
    'Denial\n"Works on my machine"',
    "Blame\nThe compiler, the OS, or cosmic rays",
    "Print Statements\nAdd them everywhere",
    "Read the Error\nFor the first time",
    "The Typo\nLine 3. It was always line 3.",
    "Cover Up\nDelete all print statements",
  ], sn++);

  // ═══════════════════════════════════════════════════════════════
  // Slide 5 — Distracted Boyfriend (IMAGE, no explicit LAYOUT)
  // Image + bullets side by side
  // ═══════════════════════════════════════════════════════════════
  addImageBulletsSlide("Distracted Boyfriend",
    resolve(OUTLINE_DIR, 'memes/distracted-boyfriend.jpg'),
    [
      "The most versatile meme format in history",
      'Man labeled "developers" looking at "new JavaScript framework"',
      'Girlfriend labeled "current JavaScript framework" looking upset',
      "Originally a stock photo by Antonio Guillem, 2015",
      "Has been used to explain every technology decision ever made",
    ], sn++);

  // ═══════════════════════════════════════════════════════════════
  // Slide 6 — Drake Hotline Bling (LAYOUT: two_column)
  // ═══════════════════════════════════════════════════════════════
  addTwoColumn(deck, "Drake Hotline Bling",
    "Drake Says No", "Drake Says Yes",
    [
      "Writing documentation",
      "Testing in production",
      "Reading the error message",
      "Attending meetings",
    ],
    [
      "Stack Overflow copy-paste",
      '"It works, don\'t touch it"',
      "Blaming DNS",
      "Adding TODO comments",
    ],
    sn++);

  // ═══════════════════════════════════════════════════════════════
  // Slide 7 — One Does Not Simply (LAYOUT: bullet + IMAGE)
  // Image + bullets side by side
  // ═══════════════════════════════════════════════════════════════
  addImageBulletsSlide("One Does Not Simply",
    resolve(OUTLINE_DIR, 'memes/one-does-not-simply.jpg'),
    [
      "One does not simply deploy to production on a Friday",
      "This meme has survived every internet trend since 2001",
      "Boromir tried to warn us about scope creep",
      'The original "I told you so" format',
    ], sn++);

  // ═══════════════════════════════════════════════════════════════
  // Slide 8 — Expanding Brain (LAYOUT: numbered, 4 steps)
  // ═══════════════════════════════════════════════════════════════
  addProcessFlow(deck, "Expanding Brain", [
    "Small Brain\nUsing git pull",
    "Normal Brain\nUsing git fetch and merge",
    "Big Brain\nUsing git worktrees for parallel development",
    "Galaxy Brain\nRebasing interactively while resolving conflicts in vim",
  ], sn++);

  // ═══════════════════════════════════════════════════════════════
  // Slide 9 — Change My Mind (LAYOUT: diagram + IMAGE)
  // Full image with context in notes
  // ═══════════════════════════════════════════════════════════════
  addImageBulletsSlide("Change My Mind",
    resolve(OUTLINE_DIR, 'memes/change-my-mind.jpg'),
    [
      "Steven Crowder sitting at a table",
      'Sign reads: "Git worktrees are the best way to do parallel AI-assisted development"',
      "The table is outside, inviting debate",
      "Nobody has successfully changed his mind",
    ], sn++);

  // ═══════════════════════════════════════════════════════════════
  // Slide 10 — Is This a Pigeon? (IMAGE)
  // Image + bullets side by side
  // ═══════════════════════════════════════════════════════════════
  addImageBulletsSlide("Is This a Pigeon?",
    resolve(OUTLINE_DIR, 'memes/is-this-a-pigeon.jpg'),
    [
      "Anime character pointing at a butterfly",
      'Character labeled: "Junior developer"',
      'Butterfly labeled: "A segfault"',
      'Caption: "Is this a feature?"',
      'From the anime "The Brave Fighter of Sun Fighbird" (1991)',
    ], sn++);

  // ═══════════════════════════════════════════════════════════════
  // Slide 11 — Conclusion: Always Has Been (LAYOUT: two_column)
  // ═══════════════════════════════════════════════════════════════
  addTwoColumn(deck, "Conclusion: Always Has Been",
    "Wait...", "Always Has Been",
    [
      "The real presentation was the memes we shared along the way",
      "PowerPoint is just a meme delivery vehicle",
      "AI can generate slides but not dank memes",
      "Wait, it's all memes?",
    ],
    [
      "Always has been",
      "Every meeting is better with memes",
      "The future of corporate communication",
      "Thank you for coming to my TED talk",
    ],
    sn++);

  // Slide 12 — Closing
  addClosingSlide(deck, sn);

  // Honor AIPPT_PREVIEW_OUT (set by the live-preview renderer) so the deck
  // lands on a writable path under a read-only root filesystem; fall back to
  // the repo-relative output/ dir for standalone CLI runs.
  const _outDir = process.env.AIPPT_PREVIEW_OUT || 'output';
  await deck.save(`${_outDir}/meme-directives-test.pptx`);
}

buildDeck().catch(console.error);
